class MealRecipes {
    static Meal kidsMeal() {
        return new Meal.Builder()
            .bun("small-regular").pattyCount(1)
            .cheese("american").sauce("ketchup")
            .size("small").build();
    }

    static Meal gourmetBurger() {
        return new Meal.Builder()
            .bun("brioche").pattyCount(2)
            .cheese("gruyere").bacon(true)
            .sauce("truffle-mayo").size("large").build();
    }
}

// Single source of truth
